  ('judicial-d35ec6db-moex-00347', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '關於數行政機關於管轄權有爭議之處置措施，下列敘述何者錯誤？', '["有共同上級機關時，由共同上級機關決定管轄權", "無共同上級機關時，由各該上級機關協議定管轄權", "人民就其依法規申請之事件，得申請指定管轄，受理申請之機關應自請求到達之日起10日內決定之", "人民對有權指定管轄權機關所為之決定如有不服，得自指定管轄之決定作成之次日起30日內提起訴願"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
