  ('judicial-d35ec6db-moex-00350', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '關於公務員責任之敘述，下列何者錯誤？', '["對於懲戒處分以及懲處處分設有不同救濟途徑", "對於懲處處分未影響公務員基礎關係僅得提起內部申訴", "公務員之刑法上責任主要反映在構成要件或加重要件上", "公務員因故意過失行使公權力致造成人民損害原則上適用國家賠償法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
