  ('judicial-d35ec6db-moex-00354', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '關於公務人員執行職務衍生之權益保障，依公務人員保障法規定，下列敘述何者正確？', '["公務人員因機關提供有瑕疵之安全防護設備致健康受損，不得依國家賠償法請求賠償", "公務人員因執行職務發生意外而受傷，如其行為當時有重大過失，得不發慰問金", "公務人員依法執行職務涉訟，如因執行職務有過失所致，即不得請求輔助", "公務人員依法執行職務涉訟時，應先自行延請律師，並向服務機關申請費用及其他法律上協助"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
