  ('judicial-d35ec6db-moex-00356', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '關於行政程序法中陳述意見之規定，下列敘述何者錯誤？', '["相對人於提起訴願前依法律應向行政機關聲請再審查者，行政機關得不給予陳述意見之機會", "應給予當事人陳述意見之機會已於事後給予者，該瑕疵得因此而補正", "陳述意見以言詞為之者，行政機關應作成紀錄", "行政機關將違法行政處分轉換為合法處分前，應一律給予當事人陳述意見之機會"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
